#include "load_cell_hx710.h"
#include <Q2HX711.h>
static Q2HX711 hx(26,25);
static int32_t _raw=0;static float _pressure=0;static unsigned long _l=0;
void hx710_setup(){Serial.println("[hx710] OK");}
void hx710_loop(){if(millis()-_l<500)return;_l=millis();_raw=hx.read();_pressure=(_raw-8388608.0)/8388608.0*40.0;}
float hx710_get_pressure(){return _pressure;}
int32_t hx710_get_raw(){return _raw;}
